// commitlint.config.js
module.exports = {
  extends: ['@commitlint/config-conventional'],
  rules: {
    // Allow custom AI-specific commit types
    'type-enum': [
      2, 'always',
      [
        'feat', 'fix', 'chore', 'docs', 'test', 'refactor',
        'style', 'perf', 'ci', 'revert',
        // AI-specific types
        'prompt',   // changes to prompt templates or system messages
        'eval',     // evaluation suite additions or modifications
        'model',    // backbone model version upgrades
        'tool',     // agent tool implementations
        'retrieval' // retrieval pipeline changes
      ]
    ],
    'scope-enum': [
      1, 'always',
      ['agent', 'retrieval', 'tools', 'system', 'routing', 'backbone', 'eval', 'infra']
    ],
    // Require Prompt-Id footer on prompt/ commits
    'footer-leading-blank': [1, 'always'],
  },
  plugins: [
    {
      rules: {
        'ai-footer-required': ({ type, footer }) => {
          if (type === 'prompt' && !footer?.includes('Prompt-Id')) {
            return [false, 'prompt commits must include a Prompt-Id footer'];
          }
          if (type === 'model' && !footer?.includes('Model-Version')) {
            return [false, 'model commits must include a Model-Version footer'];
          }
          return [true];
        }
      }
    }
  ]
};
